SELECT spell_id
FROM cooldown_effects
WHERE duration = '1 sec';

SELECT SUM(usage_count) AS total_usage
FROM spell_usage_stats
WHERE spell_id = 1;

SELECT usage_count
FROM spell_usage_stats
WHERE spell_id = 1;

SELECT SUM(usage_count) AS total_usage
FROM spell_usage_stats
WHERE spell_id = 0;

SELECT spell_id, usage_count
FROM spell_usage_stats
ORDER BY usage_count DESC;
